package com.parkflow.mall.gateway.controller;
import com.parkflow.mall.gateway.payment.PaymentServiceProxy; import org.springframework.http.*; import org.springframework.web.bind.annotation.*;
@RestController public class PaymentGatewayController {private final PaymentServiceProxy p;public PaymentGatewayController(PaymentServiceProxy p){this.p=p;}@PostMapping("/api/payments/orders") public ResponseEntity<String> create(@RequestBody String b,@RequestHeader(value="Authorization",required=false)String a,@RequestHeader(value="Idempotency-Key",required=false)String k){return p.forward("/api/payments/orders",HttpMethod.POST,b,a,k);}@GetMapping("/api/payments/orders/{id}") public ResponseEntity<String> get(@PathVariable String id,@RequestHeader(value="Authorization",required=false)String a){return p.forward("/api/payments/orders/"+id,HttpMethod.GET,null,a,null);}@PostMapping("/api/payments/simulations/success") public ResponseEntity<String> simulate(@RequestBody String b,@RequestHeader(value="Authorization",required=false)String a,@RequestHeader(value="Idempotency-Key",required=false)String k){return p.forward("/api/payments/simulations/success",HttpMethod.POST,b,a,k);}}
